import { useLocation } from "react-router-dom";
import Header from "./Header/Header";
import "./Layout.css";

export default function Layout({ children }) {
  return (
    <div className="layout">
      <Header />
      <main className="main-content">
        {children}
      </main>
    </div>
  );
}
